module RefModule(clk, reset, count);input clk, reset;
  output reg [3:0] count;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset) begin
      count <= 4'b0;
    end else if (count == 4'b1111) begin
      count <= 4'b0;
    end else begin
      count <= count + 1;
    end
  end
endmodule
